    private val allSurahs = surahs.map { surah ->
        if (surah.id in MADANIY_SURAH_IDS) surah.copy(revelationType = "Маданий")
        else surah
    }

    fun getSurahs(): List<Surah> = allSurahs
    fun getSurahById(id: Int): Surah? = allSurahs.firstOrNull { it.id == id }
    fun getNextSurahId(currentId: Int): Int? {
        val currentIndex = allSurahs.indexOfFirst { it.id == currentId }
        if (currentIndex == -1) return null
        return allSurahs.getOrNull(currentIndex + 1)?.id
    }

    companion object {
        private val MADANIY_SURAH_IDS = setOf(
            2, 3, 4, 5, 8, 9, 13, 22, 24, 33, 47, 48, 49,
            55, 57, 58, 59, 60, 61, 62, 63, 64, 65, 66, 76, 98, 110,
        )
    }
}
